section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-openapi-spec.json",
  "title": "API OpenAPI Spec Authoring",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "spec_root",
    "shards",
    "bundler",
    "spectral_ruleset",
    "oasdiff_baseline",
    "ci_jobs",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "spec_root": {
      "type": "string",
      "description": "path to the root openapi.yaml",
      "minLength": 1
    },
    "shards": {
      "type": "object",
      "description": "{paths_dir, components_dir} \u2014 relative paths"
    },
    "bundler": {
      "type": "string",
      "description": "redocly|swagger-cli|oasdiff-bundle",
      "minLength": 1
    },
    "spectral_ruleset": {
      "type": "string",
      "description": "path to .spectral.yaml",
      "minLength": 1
    },
    "oasdiff_baseline": {
      "type": "string",
      "description": "branch/tag against which breaking changes are measured",
      "minLength": 1
    },
    "ci_jobs": {
      "type": "array",
      "description": "list of CI job names enforcing lint + breaking-change gate",
      "minItems": 1
    }
  },
  "additionalProperties": false
}
